import sys
MOD = 998244353

def solve():
    data = sys.stdin.read().split()
    ptr = 0
    t = int(data[ptr]); ptr += 1
    for _ in range(t):
        n = int(data[ptr]); ptr += 1
        a = list(map(int, data[ptr:ptr+n])); ptr += n

        # dp[(m, has_m_plus_1)] = count
        dp = {}

        for num in a:
            new_dp = {}
            # Start new subsequence with just num
            mex = 0 if num != 0 else 1
            if abs(num - mex) <= 1:
                key = (mex, False)
                new_dp[key] = (new_dp.get(key, 0) + 1) % MOD

            for (m, has_next), cnt in dp.items():
                if num == m - 1 or (num < m and num != m):
                    # num < m, already in set, MEX stays m
                    if abs(num - m) <= 1:
                        key = (m, has_next)
                        new_dp[key] = (new_dp.get(key, 0) + cnt) % MOD
                elif num == m:
                    # MEX becomes m+1 if not has_next, else m+2
                    if not has_next:
                        new_mex = m + 1
                    else:
                        new_mex = m + 2
                    if abs(num - new_mex) <= 1:
                        key = (new_mex, False)
                        new_dp[key] = (new_dp.get(key, 0) + cnt) % MOD
                elif num == m + 1:
                    # MEX stays m, but now m+1 is present
                    if abs(num - m) <= 1:
                        key = (m, True)
                        new_dp[key] = (new_dp.get(key, 0) + cnt) % MOD

            for k, v in new_dp.items():
                dp[k] = (dp.get(k, 0) + v) % MOD

        print(sum(dp.values()) % MOD)

solve()

